{{
(() => {
  const info = getModelInfoForArticle.data?.[0];
  const division = getDivisionStatus.data?.find(d => d.division === "COS");

  if (!info) {
    return "<div style='display:flex;align-items:center;justify-content:center;padding:14px 18px;border-radius:12px;background:linear-gradient(135deg,#553DE9,#6F5CF4);box-shadow:0 4px 12px rgba(85,61,233,0.18);'>"
    + "<div style='display:flex;align-items:center;gap:12px;'>"
    + "<div style='width:42px;height:42px;border-radius:12px;background:rgba(255,255,255,0.16);display:flex;align-items:center;justify-content:center;font-size:20px;'>📄</div>"
    + "<div>"
    + "<div style='font-size:15px;font-weight:700;color:white;'>No Article Selected</div>"
    + "<div style='font-size:12px;color:rgba(255,255,255,0.75);margin-top:3px;'>Select an article to display model information.</div>"
    + "</div></div></div>";
  }

  const status = division?.state ?? "NOT_STARTED";

  const statusColor =
    status === "SUBMITTED"
      ? "#16a34a"
      : status === "IN_WORK"
      ? "#f59e0b"
      : status === "REWORK"
      ? "#dc2626"
      : "#64748b";

  const carry =
    division?.submitted_by?.startsWith("CARRIED_OVER:")
      ? " ↻"
      : "";

  return "<div style='display:flex;align-items:center;justify-content:space-between;padding:14px 18px;border-radius:12px;background:linear-gradient(135deg,#553DE9,#6F5CF4);box-shadow:0 4px 12px rgba(85,61,233,0.18);'>"

  + "<div style='display:flex;align-items:center;gap:12px;'>"

  + "<div style='width:42px;height:42px;border-radius:12px;background:rgba(255,255,255,0.16);display:flex;align-items:center;justify-content:center;font-size:20px;'>👟</div>"

  + "<div>"

  + "<div style='font-size:16px;font-weight:700;color:white;'>"
  + (info.model_name || "-")
  + "</div>"

  + "<div style='font-size:12px;color:rgba(255,255,255,0.75);margin-top:3px;'>Model Number • "
  + (info.model_number || "-")
  + "</div>"

  + "</div></div>"

  + "<div style='display:flex;gap:8px;align-items:center;'>"

  + "<div style='padding:6px 12px;border-radius:999px;background:rgba(255,255,255,0.18);color:white;font-size:12px;font-weight:600;'>"
  + "Season: "
  + (info.season || "-")
  + "</div>"

  + "<div style='padding:6px 12px;border-radius:999px;background:"
  + statusColor
  + ";color:white;font-size:12px;font-weight:700;'>"
  + status.replaceAll("_"," ")
  + carry
  + "</div>"

  + "</div></div>";
})()
}}
